1	export type Customer = {
2	  yearsWithMHPCO: number;
3	};
4	
5	export type Item = {
6	  type: string;
7	  material?: string;
8	  cursed?: boolean;
9	  enchantment?: number;
10	};
11	
12	export type QuoteStep = {
13	  op: "quote";
14	  items: Item[];
15	};
16	
17	export type Damage = {
18	  itemType: string;
19	  amount: number;
20	};
21	
22	export type Incident = {
23	  cause: string;
24	  damages: Damage[];
25	};
26	
27	export type ClaimStep = {
28	  op: "claim";
29	  policy: number;
30	  incident: Incident;
31	};
32	
33	export type Step = QuoteStep | ClaimStep;
34	
35	export type Scenario = {
36	  customer: Customer;
37	  steps: Step[];
38	};
39	
40	export type ClaimResult = {
41	  payout: number;
42	  remainingCap: number;
43	};
44	
45	export type Result = {
46	  premium?: number;
47	  payout?: number;
48	  remainingCap?: number;
49	};
50	
51	const PROCESSING_FEE = 5;
52	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
53	const CURSE_SURCHARGE_RATE = 0.5;
54	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
55	const HIGH_ENCHANTMENT_MINIMUM = 5;
56	const LOYALTY_DISCOUNT_RATE = 0.2;
57	const LOYALTY_MINIMUM_YEARS = 2;
58	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
59	
60	const BASE_PREMIUMS: Record<string, number> = {
61	  sword: 100,
62	  amulet: 60,
63	  staff: 80,
64	  potion: 40,
65	  rune: 25,
66	  moonstone: 25,
67	};
68	
69	const COMPONENT_BLOCK_SIZE = 3;
70	const COMPONENT_BLOCK_PREMIUM = 60;
71	
72	const countByType = (items: Item[]): Map<string, number> => {
73	  const counts = new Map<string, number>();
74	  for (const item of items) {
75	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
76	  }
77	  return counts;
78	};
79	
80	const groupBasePremium = (type: string, count: number): number =>
81	  count === COMPONENT_BLOCK_SIZE
82	    ? COMPONENT_BLOCK_PREMIUM
83	    : count * BASE_PREMIUMS[type];
84	
85	const computeBasePremium = (items: Item[]): number =>
86	  [...countByType(items)].reduce(
87	    (total, [type, count]) => total + groupBasePremium(type, count),
88	    0,
89	  );
90	
91	const sumBy = <T>(values: T[], amount: (value: T) => number): number =>
92	  values.reduce((total, value) => total + amount(value), 0);
93	
94	const itemCurseSurcharge = (item: Item): number =>
95	  item.cursed ? BASE_PREMIUMS[item.type] * CURSE_SURCHARGE_RATE : 0;
96	
97	const enchantmentOf = (item: Item): number => item.enchantment ?? 0;
98	
99	const itemHighEnchantmentSurcharge = (item: Item): number =>
100	  enchantmentOf(item) >= HIGH_ENCHANTMENT_MINIMUM
101	    ? BASE_PREMIUMS[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE
102	    : 0;
103	
104	const quotePremium = (
105	  customer: Customer,
106	  items: Item[],
107	  isFollowUp: boolean,
108	): number => {
109	  const basePremium = computeBasePremium(items);
110	  const curseSurcharge = sumBy(items, itemCurseSurcharge);
111	  const highEnchantmentSurcharge = sumBy(items, itemHighEnchantmentSurcharge);
112	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
113	  const loyaltyDiscount =
114	    customer.yearsWithMHPCO >= LOYALTY_MINIMUM_YEARS
115	      ? basePremium * LOYALTY_DISCOUNT_RATE
116	      : 0;
117	  const followUpDiscount = isFollowUp
118	    ? basePremium * FOLLOW_UP_DISCOUNT_RATE
119	    : 0;
120	  const exactPremium =
121	    basePremium +
122	    curseSurcharge +
123	    highEnchantmentSurcharge +
124	    firstInsuranceSurcharge -
125	    loyaltyDiscount -
126	    followUpDiscount +
127	    PROCESSING_FEE;
128	  return Math.ceil(exactPremium);
129	};
130	
131	const DEDUCTIBLE = 100;
132	const PAYOUT_CAP_MULTIPLIER = 2;
133	const HALF_REIMBURSEMENT_MINIMUM_ENCHANTMENT = 8;
134	const HALF_REIMBURSEMENT_RATE = 0.5;
135	
136	const INSURANCE_VALUES: Record<string, number> = {
137	  sword: 1000,
138	  amulet: 600,
139	  rune: 250,
140	};
141	
142	const insuranceValueOf = (item: Item): number => INSURANCE_VALUES[item.type];
143	
144	const reimbursementFor = (insuredItem: Item, damage: Damage): number =>
145	  enchantmentOf(insuredItem) >= HALF_REIMBURSEMENT_MINIMUM_ENCHANTMENT
146	    ? damage.amount * HALF_REIMBURSEMENT_RATE
147	    : damage.amount;
148	
149	const findInsuredItem = (insuredItems: Item[], damage: Damage): Item =>
150	  insuredItems.find((item) => item.type === damage.itemType) as Item;
151	
152	const damagePayout = (insuredItems: Item[], damage: Damage): number =>
153	  reimbursementFor(findInsuredItem(insuredItems, damage), damage) - DEDUCTIBLE;
154	
155	const processClaim = (policy: QuoteStep, claim: ClaimStep): ClaimResult => {
156	  const payoutCap =
157	    PAYOUT_CAP_MULTIPLIER * sumBy(policy.items, insuranceValueOf);
158	  const payout = sumBy(claim.incident.damages, (damage) =>
159	    damagePayout(policy.items, damage),
160	  );
161	  return { payout, remainingCap: payoutCap - payout };
162	};
163	
164	export const processScenario = (scenario: Scenario): { results: Result[] } => ({
165	  results: scenario.steps.map((step, index) =>
166	    step.op === "quote"
167	      ? { premium: quotePremium(scenario.customer, step.items, index > 0) }
168	      : processClaim(scenario.steps[step.policy] as QuoteStep, step),
169	  ),
170	});
